    const handleCheckboxChange = (checked: boolean, value: string) => {
      const filterValue = column.getFilterValue() as string[];
      const newFilterValue = Array.isArray(filterValue) ? [...filterValue] : [];

      if (checked) {
        newFilterValue.push(value);
      } else {
